40: func toEvaluationFlagType(f flipt.FlagType) evaluation.EvaluationFlagType {
41: 	switch f {
42: 	case flipt.FlagType_BOOLEAN_FLAG_TYPE:
43: 		return evaluation.EvaluationFlagType_BOOLEAN_FLAG_TYPE
44: 	case flipt.FlagType_VARIANT_FLAG_TYPE:
45: 		return evaluation.EvaluationFlagType_VARIANT_FLAG_TYPE
46: 	}
47: 	return evaluation.EvaluationFlagType_VARIANT_FLAG_TYPE
48: }
49: 
50: func toEvaluationSegmentMatchType(s flipt.MatchType) evaluation.EvaluationSegmentMatchType {
51: 	switch s {
52: 	case flipt.MatchType_ANY_MATCH_TYPE:
53: 		return evaluation.EvaluationSegmentMatchType_ANY_SEGMENT_MATCH_TYPE
54: 	case flipt.MatchType_ALL_MATCH_TYPE:
55: 		return evaluation.EvaluationSegmentMatchType_ALL_SEGMENT_MATCH_TYPE
56: 	}
57: 	return evaluation.EvaluationSegmentMatchType_ANY_SEGMENT_MATCH_TYPE
58: }
59: 
60: func toEvaluationSegmentOperator(s flipt.SegmentOperator) evaluation.EvaluationSegmentOperator {
61: 	switch s {
62: 	case flipt.SegmentOperator_OR_SEGMENT_OPERATOR:
63: 		return evaluation.EvaluationSegmentOperator_OR_SEGMENT_OPERATOR
64: 	case flipt.SegmentOperator_AND_SEGMENT_OPERATOR:
65: 		return evaluation.EvaluationSegmentOperator_AND_SEGMENT_OPERATOR
66: 	}
67: 	return evaluation.EvaluationSegmentOperator_OR_SEGMENT_OPERATOR
68: }
69: 
70: func toEvaluationConstraintComparisonType(c flipt.ComparisonType) evaluation.EvaluationConstraintComparisonType {
71: 	switch c {
72: 	case flipt.ComparisonType_STRING_COMPARISON_TYPE:
73: 		return evaluation.EvaluationConstraintComparisonType_STRING_CONSTRAINT_COMPARISON_TYPE
74: 	case flipt.ComparisonType_NUMBER_COMPARISON_TYPE:
75: 		return evaluation.EvaluationConstraintComparisonType_NUMBER_CONSTRAINT_COMPARISON_TYPE
76: 	case flipt.ComparisonType_DATETIME_COMPARISON_TYPE:
77: 		return evaluation.EvaluationConstraintComparisonType_DATETIME_CONSTRAINT_COMPARISON_TYPE
78: 	case flipt.ComparisonType_BOOLEAN_COMPARISON_TYPE:
79: 		return evaluation.EvaluationConstraintComparisonType_BOOLEAN_CONSTRAINT_COMPARISON_TYPE
80: 	case flipt.ComparisonType_ENTITY_ID_COMPARISON_TYPE:
81: 		return evaluation.EvaluationConstraintComparisonType_ENTITY_ID_CONSTRAINT_COMPARISON_TYPE
82: 	}
83: 	return evaluation.EvaluationConstraintComparisonType_UNKNOWN_CONSTRAINT_COMPARISON_TYPE
84: }
85: 
86: func toEvaluationRolloutType(r flipt.RolloutType) evaluation.EvaluationRolloutType {
87: 	switch r {
88: 	case flipt.RolloutType_THRESHOLD_ROLLOUT_TYPE:
89: 		return evaluation.EvaluationRolloutType_THRESHOLD_ROLLOUT_TYPE
90: 	case flipt.RolloutType_SEGMENT_ROLLOUT_TYPE:
91: 		return evaluation.EvaluationRolloutType_SEGMENT_ROLLOUT_TYPE
92: 	}
93: 	return evaluation.EvaluationRolloutType_UNKNOWN_ROLLOUT_TYPE
94: }
