294: // ListWithQueryParamOptions takes a set of functional options for QueryParam and returns a ListOption
295: // which applies them in order on the provided ListRequest.
296: func ListWithQueryParamOptions[T any](opts ...QueryOption) ListOption[T] {
297: 	return func(r *ListRequest[T]) {
