31: // ValidationUnaryInterceptor validates incoming requests
32: func ValidationUnaryInterceptor(ctx context.Context, req interface{}, _ *grpc.UnaryServerInfo, handler grpc.UnaryHandler) (resp interface{}, err error) {
33: 	if v, ok := req.(flipt.Validator); ok {
34: 		if err := v.Validate(); err != nil {
35: 			return nil, err
36: 		}
37: 	}
38: 
39: 	return handler(ctx, req)
