42: // ErrorUnaryInterceptor intercepts known errors and returns the appropriate GRPC status code
43: func ErrorUnaryInterceptor(ctx context.Context, req interface{}, _ *grpc.UnaryServerInfo, handler grpc.UnaryHandler) (resp interface{}, err error) {
44: 	resp, err = handler(ctx, req)
45: 	if err == nil {
46: 		return resp, nil
47: 	}
48: 
49: 	metrics.ErrorsTotal.Add(ctx, 1)
50: 
51: 	// given already a *status.Error then forward unchanged
52: 	if _, ok := status.FromError(err); ok {
53: 		return
54: 	}
55: 
56: 	if errors.Is(err, context.Canceled) {
57: 		err = status.Error(codes.Canceled, err.Error())
58: 		return
59: 	}
60: 
61: 	if errors.Is(err, context.DeadlineExceeded) {
62: 		err = status.Error(codes.DeadlineExceeded, err.Error())
63: 		return
64: 	}
65: 
66: 	code := codes.Internal
67: 	switch {
68: 	case errs.AsMatch[errs.ErrNotFound](err):
69: 		code = codes.NotFound
70: 	case errs.AsMatch[errs.ErrInvalid](err),
71: 		errs.AsMatch[errs.ErrValidation](err):
72: 		code = codes.InvalidArgument
73: 	case errs.AsMatch[errs.ErrUnauthenticated](err):
74: 		code = codes.Unauthenticated
75: 	}
76: 
77: 	err = status.Error(code, err.Error())
78: 	return
79: }
