81: type RequestIdentifiable interface {
82: 	// SetRequestIDIfNotBlank attempts to set the provided ID on the instance
83: 	// If the ID was blank, it returns the ID provided to this call.
84: 	// If the ID was not blank, it returns the ID found on the instance.
85: 	SetRequestIDIfNotBlank(id string) string
86: }
