93: // EvaluationUnaryInterceptor sets required request/response fields.
94: // Note: this should be added before any caching interceptor to ensure the request id/response fields are unique.
95: func EvaluationUnaryInterceptor(analyticsEnabled bool) grpc.UnaryServerInterceptor {
96: 	return func(ctx context.Context, req interface{}, _ *grpc.UnaryServerInfo, handler grpc.UnaryHandler) (resp interface{}, err error) {
97: 		startTime := time.Now().UTC()
98: 
99: 		// set request ID if not present
100: 		requestID := uuid.Must(uuid.NewV4()).String()
101: 		if r, ok := req.(RequestIdentifiable); ok {
102: 			requestID = r.SetRequestIDIfNotBlank(requestID)
103: 
104: 			resp, err = handler(ctx, req)
105: 			if err != nil {
106: 				return resp, err
107: 			}
108: 
109: 			// set request ID on response
110: 			if r, ok := resp.(RequestIdentifiable); ok {
111: 				_ = r.SetRequestIDIfNotBlank(requestID)
112: 			}
113: 
114: 			// record start, end, duration on response types
115: 			if r, ok := resp.(ResponseDurationRecordable); ok {
116: 				r.SetTimestamps(startTime, time.Now().UTC())
117: 			}
118: 
119: 			if analyticsEnabled {
120: 				span := trace.SpanFromContext(ctx)
121: 
122: 				switch r := resp.(type) {
123: 				case *evaluation.VariantEvaluationResponse:
124: 					// This "should" always be an evalution request under these circumstances.
125: 					if evaluationRequest, ok := req.(*evaluation.EvaluationRequest); ok {
126: 						var variantKey *string = nil
127: 						if r.GetVariantKey() != "" {
128: 							variantKey = &r.VariantKey
129: 						}
130: 
131: 						evaluationResponses := []*analytics.EvaluationResponse{
132: 							{
133: 								NamespaceKey:    evaluationRequest.GetNamespaceKey(),
134: 								FlagKey:         r.GetFlagKey(),
135: 								FlagType:        evaluation.EvaluationFlagType_VARIANT_FLAG_TYPE.String(),
136: 								Match:           &r.Match,
137: 								Reason:          r.GetReason().String(),
138: 								Timestamp:       r.GetTimestamp().AsTime(),
139: 								EvaluationValue: variantKey,
140: 								EntityId:        evaluationRequest.EntityId,
141: 							},
142: 						}
143: 
144: 						if evaluationResponsesBytes, err := json.Marshal(evaluationResponses); err == nil {
145: 							keyValue := []attribute.KeyValue{
146: 								{
147: 									Key:   "flipt.evaluation.response",
148: 									Value: attribute.StringValue(string(evaluationResponsesBytes)),
149: 								},
150: 							}
151: 							span.AddEvent("evaluation_response", trace.WithAttributes(keyValue...))
152: 						}
153: 					}
154: 				case *evaluation.BooleanEvaluationResponse:
155: 					if evaluationRequest, ok := req.(*evaluation.EvaluationRequest); ok {
156: 						evaluationValue := fmt.Sprint(r.GetEnabled())
157: 						evaluationResponses := []*analytics.EvaluationResponse{
158: 							{
159: 								NamespaceKey:    evaluationRequest.GetNamespaceKey(),
160: 								FlagKey:         r.GetFlagKey(),
161: 								FlagType:        evaluation.EvaluationFlagType_BOOLEAN_FLAG_TYPE.String(),
162: 								Reason:          r.GetReason().String(),
163: 								Timestamp:       r.GetTimestamp().AsTime(),
164: 								Match:           nil,
165: 								EvaluationValue: &evaluationValue,
166: 								EntityId:        evaluationRequest.EntityId,
167: 							},
168: 						}
169: 
170: 						if evaluationResponsesBytes, err := json.Marshal(evaluationResponses); err == nil {
171: 							keyValue := []attribute.KeyValue{
172: 								{
173: 									Key:   "flipt.evaluation.response",
174: 									Value: attribute.StringValue(string(evaluationResponsesBytes)),
175: 								},
176: 							}
177: 							span.AddEvent("evaluation_response", trace.WithAttributes(keyValue...))
178: 						}
179: 					}
180: 				case *evaluation.BatchEvaluationResponse:
181: 					if batchEvaluationRequest, ok := req.(*evaluation.BatchEvaluationRequest); ok {
182: 						evaluationResponses := make([]*analytics.EvaluationResponse, 0, len(r.GetResponses()))
183: 						for idx, response := range r.GetResponses() {
184: 							switch response.GetType() {
185: 							case evaluation.EvaluationResponseType_VARIANT_EVALUATION_RESPONSE_TYPE:
186: 								variantResponse := response.GetVariantResponse()
187: 								var variantKey *string = nil
188: 								if variantResponse.GetVariantKey() != "" {
189: 									variantKey = &variantResponse.VariantKey
190: 								}
191: 
192: 								evaluationResponses = append(evaluationResponses, &analytics.EvaluationResponse{
193: 									NamespaceKey:    batchEvaluationRequest.Requests[idx].GetNamespaceKey(),
194: 									FlagKey:         variantResponse.GetFlagKey(),
195: 									FlagType:        evaluation.EvaluationFlagType_VARIANT_FLAG_TYPE.String(),
196: 									Match:           &variantResponse.Match,
197: 									Reason:          variantResponse.GetReason().String(),
198: 									Timestamp:       variantResponse.Timestamp.AsTime(),
199: 									EvaluationValue: variantKey,
200: 									EntityId:        batchEvaluationRequest.Requests[idx].EntityId,
201: 								})
202: 							case evaluation.EvaluationResponseType_BOOLEAN_EVALUATION_RESPONSE_TYPE:
203: 								booleanResponse := response.GetBooleanResponse()
204: 								evaluationValue := fmt.Sprint(booleanResponse.GetEnabled())
205: 								evaluationResponses = append(evaluationResponses, &analytics.EvaluationResponse{
206: 									NamespaceKey:    batchEvaluationRequest.Requests[idx].GetNamespaceKey(),
207: 									FlagKey:         booleanResponse.GetFlagKey(),
208: 									FlagType:        evaluation.EvaluationFlagType_BOOLEAN_FLAG_TYPE.String(),
209: 									Reason:          booleanResponse.GetReason().String(),
210: 									Timestamp:       booleanResponse.Timestamp.AsTime(),
211: 									Match:           nil,
212: 									EvaluationValue: &evaluationValue,
213: 									EntityId:        batchEvaluationRequest.Requests[idx].EntityId,
214: 								})
215: 							}
216: 						}
217: 
218: 						if evaluationResponsesBytes, err := json.Marshal(evaluationResponses); err == nil {
219: 							keyValue := []attribute.KeyValue{
220: 								{
221: 									Key:   "flipt.evaluation.response",
222: 									Value: attribute.StringValue(string(evaluationResponsesBytes)),
223: 								},
224: 							}
225: 							span.AddEvent("evaluation_response", trace.WithAttributes(keyValue...))
226: 						}
227: 					}
228: 				}
229: 			}
230: 
231: 			return resp, nil
232: 		}
233: 
234: 		return handler(ctx, req)
235: 	}
236: }
